def _load_db():
    if _DB_PRODUCTS:
        print(f"[DB] 内嵌数据: {len(_DB_PRODUCTS)}只产品")
        return {"products": _DB_PRODUCTS, "peer_groups": _DB_PEER_GROUPS, "index_to_codes": _DB_INDEX_TO_CODES}
    for base_dir in [os.path.dirname(os.path.abspath(__file__)), os.getcwd(), "/app", "."]:
        p = os.path.join(base_dir, "etf_db.json")
        if os.path.exists(p):
            try:
                with open(p, encoding="utf-8") as f:
                    db = json.load(f)
                print(f"[DB] 文件: {len(db.get('products',{}))}只产品")
                return db
            except Exception as e:
                print(f"[DB] 读取失败: {e}")
    print("[DB] 警告: 无数据源")
    return {"products": {}, "peer_groups": {}, "index_to_codes": {}}

DB = _load_db()

