def _safe_float(v):
    try: return round(float(str(v).replace("%","").replace(",","").strip()), 4)
    except: return None

def _latest_quarter():
    m, y = date.today().month, date.today().year
    q = {1:"4",2:"4",3:"4",4:"4",5:"1",6:"1",7:"1",8:"2",9:"2",10:"3",11:"3",12:"3"}[m]
    return (str(y-1) if q=="4" else str(y)), q

def fetch_spot():
    try:
        import akshare as ak
        df = ak.fund_etf_spot_em()
        r = {}
        for _, row in df.iterrows():
            c = str(row.get("代码","")).strip()
            r[c] = {
                "price":    _safe_float(row.get("最新价")),
                "pct_chg":  _safe_float(row.get("涨跌幅")),
                "premium":  _safe_float(row.get("折溢价率")),
                "turnover": str(row.get("成交额","")),
                "aum":      _safe_float(row.get("规模", row.get("规模(亿)"))),
            }
        return r
    except Exception as e:
        print(f"[spot] {e}")
        return {}

def fetch_index_perf(code):
    try:
        import akshare as ak, pandas as pd
        end = date.today()
        df = ak.index_zh_a_hist(
            symbol=code, period="daily",
            start_date=end.replace(year=end.year-1).strftime("%Y%m%d"),
            end_date=end.strftime("%Y%m%d"),
        )
        if df is None or df.empty: return None
        df = df.sort_values("日期")
        c = df["收盘"].values
        def r(n): return round((c[-1]/c[-n]-1)*100, 2) if len(c)>=n else None
        roll = pd.Series(c).cummax()
        dd = round(((pd.Series(c)-roll)/roll).min()*100, 2)
        mi = pd.Series(c).idxmin()
        bounce = round((c[-1]/c[mi]-1)*100, 2) if mi < len(c)-1 else 0
        return {"ret_1m":r(22),"ret_3m":r(63),"ret_6m":r(126),"ret_1y":r(252),
                "max_dd":dd,"bounce":bounce,"price":round(float(c[-1]),2)}
    except: return None

def fetch_top10(code):
    try:
        import akshare as ak
        yr, q = _latest_quarter()
        df = ak.fund_portfolio_hold_em(code=code, year=yr, quarter=q)
        if df is None or df.empty:
            q2 = str(int(q)-1) if q!="1" else "4"
            yr2 = yr if q!="1" else str(int(yr)-1)
            df = ak.fund_portfolio_hold_em(code=code, year=yr2, quarter=q2)
        if df is None or df.empty: return {}
        stocks = []
        for _, row in df.head(10).iterrows():
            try: w = float(str(row.get("占净值比例",0)).replace("%",""))
            except: w = 0
            stocks.append({"name": str(row.get("股票名称","")), "weight": w})
        return {"stocks": stocks, "date": f"{yr}-Q{q}"}
    except Exception as e:
        return {"error": str(e)}

def fetch_industry(code):
    try:
        import akshare as ak
        yr, q = _latest_quarter()
        df = ak.fund_industry_allocation_em(code=code, year=yr, quarter=q)
        if df is None or df.empty: return {}
        inds = []
        for _, row in df.iterrows():
            try: w = float(str(row.get("占净值比例",0)).replace("%",""))
            except: w = 0
            inds.append({"name": str(row.get("行业名称","")), "weight": w})
        inds.sort(key=lambda x: x["weight"], reverse=True)
        return {"industries": inds[:8], "date": f"{yr}-Q{q}"}
    except: return {}

def fetch_all_data():
    with LOCK: CACHE["status"] = "loading"; CACHE["error"] = ""
    try:
        import akshare as ak
        # 1. ETF行情
        print("[1/3] ETF行情...")
        spot = fetch_spot()
        print(f"      {len(spot)}只")

        # 2. 指数历史（并发）
        print("[2/3] 指数历史...")
        index_codes = set()
        for code in DB.get("products",{}).keys():
            pg = DB.get("peer_groups",{}).get(code,{})
            idx_raw = (pg.get("self") or {}).get("index","")
            m = re.search(r'(\d{6})', idx_raw)
            if m: index_codes.add(m.group(1))
        index_perf = {}
        with ThreadPoolExecutor(max_workers=5) as ex:
            futs = {ex.submit(fetch_index_perf, ic): ic for ic in list(index_codes)[:30]}
            for fut in as_completed(futs):
                ic = futs[fut]
                r = fut.result()
                if r: index_perf[ic] = r
        print(f"      {len(index_perf)}个指数")

        # 3. 同业规模（从spot计算）
        print("[3/3] 同业排名...")
        peer_aum = {}
        for idx_name, entries in DB.get("index_to_codes",{}).items():
            peers = []
            for e in entries:
                c = e["code"]
                sp = spot.get(c, {})
                peers.append({"code":c,"name":e["name"],"manager":e["manager"],
                              "aum":sp.get("aum"),"premium":sp.get("premium"),
                              "pct_chg":sp.get("pct_chg")})
            peers.sort(key=lambda x: x["aum"] or 0, reverse=True)
            peer_aum[idx_name] = peers

        with LOCK:
            CACHE["spot"] = spot
            CACHE["index_perf"] = index_perf
            CACHE["peer_aum"] = peer_aum
            CACHE["last_update"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            CACHE["status"] = "ok"
        print("[完成]")

        # 4. 持仓（后台静默拉取，不阻塞主流程）
        threading.Thread(target=_fetch_holdings_bg, daemon=True).start()

    except Exception as e:
        with LOCK: CACHE["status"] = "error"; CACHE["error"] = str(e)
        print(f"[错误] {e}")

def _fetch_holdings_bg():
    print("[持仓] 开始后台拉取...")
    codes = list(DB.get("products",{}).keys())[:30]
    holdings = {}
    for code in codes:
        try:
            time.sleep(0.4)
            top10 = fetch_top10(code)
            time.sleep(0.3)
            industry = fetch_industry(code)
            holdings[code] = {"top10": top10, "industry": industry}
        except: pass
    with LOCK: CACHE["holdings"] = holdings
    print(f"[持仓] 完成 {len(holdings)}只")

def _dynamic_peers(idx_name, own_code):
    with LOCK:
        peers = CACHE["peer_aum"].get(idx_name, [])
    return [p for p in peers if p.get("code") != own_code and p.get("aum")][:2]

