@app.route("/api/products")
@login_required
def api_products():
    with LOCK:
        spot = CACHE["spot"]
        peer_aum = CACHE["peer_aum"]
    result = []
    for code, p in DB.get("products",{}).items():
        sp = spot.get(code, {})
        idx_name = p.get("index_name","")
        peers = peer_aum.get(idx_name, [])
        rank = next((i+1 for i,pe in enumerate(peers) if pe.get("code")==code), None)
        result.append({**p,
            "price": sp.get("price"), "pct_chg": sp.get("pct_chg"),
            "premium": sp.get("premium"), "turnover": sp.get("turnover"),
            "aum_rt": sp.get("aum"),
            "peer_rank": rank, "peer_total": len(peers),
        })
    result.sort(key=lambda x: x.get("aum_rt") or 0, reverse=True)
    return jsonify(result)

@app.route("/api/product/<code>")
@login_required
def api_product_detail(code):
    p = DB.get("products",{}).get(code)
    if not p: return jsonify({"error":"产品不存在"}), 404
    with LOCK:
        spot = CACHE["spot"]
        peer_aum = CACHE["peer_aum"]
        index_perf = CACHE["index_perf"]
        holdings_data = CACHE["holdings"].get(code, {})
    sp = spot.get(code, {})
    idx_name = p.get("index_name","")
    peers_rt = peer_aum.get(idx_name, [])
    dyn_peers = _dynamic_peers(idx_name, code)
    pg = DB.get("peer_groups",{}).get(code, {})
    self_data = pg.get("self") or {}
    peers_excel = pg.get("peers", [])
    idx_raw = self_data.get("index","")
    m = re.search(r'(\d{6})', idx_raw)
    idx_code = m.group(1) if m else ""
    idx_perf = index_perf.get(idx_code, {})
    return jsonify({
        "product": p, "spot": sp,
        "index_code": idx_code, "index_raw": idx_raw, "index_perf": idx_perf,
        "peers_rt": peers_rt[:8], "peers_excel": peers_excel,
        "pg_self": self_data, "holdings": holdings_data,
        "dynamic_peers": dyn_peers, "last_update": CACHE.get("last_update",""),
    })

@app.route("/api/ai_slogan/<code>", methods=["POST"])
@login_required
def api_ai_slogan(code):
    if not ANTHROPIC_API_KEY:
        return jsonify({"error": "请在Railway环境变量中配置 ANTHROPIC_API_KEY"})
    p = DB.get("products",{}).get(code)
    if not p: return jsonify({"error":"产品不存在"})
    with LOCK:
        idx_name = p.get("index_name","")
        peer_list = CACHE["peer_aum"].get(idx_name, [])
        pg = DB.get("peer_groups",{}).get(code, {})
        idx_raw = (pg.get("self") or {}).get("index","")
        m = re.search(r'(\d{6})', idx_raw)
        idx_code = m.group(1) if m else ""
        idx_perf = CACHE["index_perf"].get(idx_code, {})
        holdings = CACHE["holdings"].get(code, {})
    dyn_peers = _dynamic_peers(idx_name, code)
    prompt = _build_prompt(p, peer_list, idx_perf, holdings, dyn_peers)
    try:
        import urllib.request
        payload = json.dumps({
            "model": "claude-sonnet-4-20250514",
            "max_tokens": 1000,
            "messages": [{"role":"user","content": prompt}]
        }).encode()
        req = urllib.request.Request(
            "https://api.anthropic.com/v1/messages", data=payload,
            headers={"Content-Type":"application/json","x-api-key":ANTHROPIC_API_KEY,
                     "anthropic-version":"2023-06-01"})
        with urllib.request.urlopen(req, timeout=30) as resp:
            data = json.loads(resp.read())
        text = "".join(b.get("text","") for b in data.get("content",[]) if b.get("type")=="text")
        m2 = re.search(r'\{[\s\S]*\}', text)
        if m2:
            result = json.loads(m2.group())
            result["raw"] = text
            return jsonify(result)
        return jsonify({"raw": text, "error": "格式异常"})
    except Exception as e:
        return jsonify({"error": str(e)})

def _build_prompt(p, peer_list, idx_perf, holdings, dyn_peers):
    code = p.get("code","")
    idx_name = p.get("index_name","")
    # 指数表现
    perf = []
    for k,l in [("ret_1m","近1月"),("ret_3m","近3月"),("ret_6m","近6月"),("ret_1y","近1年")]:
        v = idx_perf.get(k)
        if v is not None: perf.append(f"{l}：{'+' if v>=0 else ''}{v:.2f}%")
    if idx_perf.get("bounce"): perf.append(f"低点弹性：+{idx_perf['bounce']:.2f}%")
    # 排名
    own_rank = next((i+1 for i,pe in enumerate(peer_list) if pe.get("code")==code), None)
    rank_txt = f"同指数共{len(peer_list)}只，规模排第{own_rank}名" if own_rank else ""
    # 竞品
    peer_txt = "\n".join(
        "竞品{}：{}（{}）规模{}".format(i+1, pe.get('name',''), pe.get('manager',''), "{:.1f}亿".format(pe['aum']) if pe.get('aum') else '—')
        for i,pe in enumerate(dyn_peers[:2])
    )
    # 持仓
    top10 = holdings.get("top10",{})
    industry = holdings.get("industry",{})
    top10_txt = "、".join(f"{s['name']}({s['weight']:.1f}%)" for s in top10.get("stocks",[])[:5]) if top10.get("stocks") else "季报数据加载中"
    ind_txt = "、".join(f"{i['name']}({i['weight']:.0f}%)" for i in industry.get("industries",[])[:4]) if industry.get("industries") else "季报数据加载中"

    return f"""你是鹏华基金ETF营销专家，请根据以下真实数据为「{p.get('name','')}」生成营销话术。

【产品信息】
名称：{p.get('name','')}（{code}） | 板块：{p.get('board','')} | 主理人：{p.get('manager','—')}
特殊标签：{(p.get('special_tag','') or '无').replace(chr(10),' ')}
场内独家：{'✅' if p.get('is_exclusive') else '❌'} | 费率最低档：{'✅' if p.get('fee_lowest') else '❌'} | 规模最大：{'✅' if p.get('aum_largest') else '❌'}
估值低位：{(p.get('valuation_low','') or '无').replace(chr(10),' ')} | 跟踪误差最小：{(p.get('tracking_err_min','') or '无').replace(chr(10),' ')}

【季报持仓（有延迟，仅供参考）】
前五大重仓：{top10_txt}
行业配置：{ind_txt}

【指数实时表现】
{chr(10).join(perf) or '暂无实时数据'}

【同业竞争】
{rank_txt}
{peer_txt or '竞品数据加载中'}

【历史话术参考】
版本1：{p.get('slogan_v1','—')}
版本2：{p.get('slogan_v2','—')}
热门股：{(p.get('hot_stock','') or '—').replace(chr(10),' ')}
赛道：{(p.get('key_sector','') or '—').replace(chr(10),' ')}

请用JSON格式输出（不要加```代码块）：
{{
  "slogan_v1": "15字内一句话核心卖点",
  "slogan_v2": "20字内第二版本",
  "product_points": ["产品维度卖点1（≤50字）","卖点2","卖点3"],
  "index_points": ["指数维度卖点1（≤60字）","卖点2"],
  "peer_pitch": "基转基话术，≤120字，针对竞品持有者"
}}
只引用上方真实数据，禁止编造数字。"""

@app.route("/api/etf_search")
@login_required
def api_etf_search():
    q = request.args.get("q","").lower()
    with LOCK: spot = CACHE["spot"]
    result = []
    for code, p in DB.get("products",{}).items():
        if q in p.get("name","").lower() or q in code:
            sp = spot.get(code,{})
            result.append({**p, **sp})
    return jsonify(result[:20])

